import React, { useState } from 'react';
import clienteAxios from '../api/axios';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const respuesta = await clienteAxios.post('/auth/login', { email, password });
            localStorage.setItem('token', respuesta.data.token);
            alert('¡Bienvenido ' + respuesta.data.user.nombre + '!');
        } catch (error) {
            console.error(error);
            alert('Error: ' + (error.response?.data?.message || 'No se pudo conectar con el servidor'));
        }
    };

    return (
        <div style={{ padding: '20px', border: '1px solid #ccc', borderRadius: '8px' }}>
            <h2>Iniciar Sesión</h2>
            <form onSubmit={handleSubmit}>
                <input type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} style={{display: 'block', marginBottom: '10px'}} />
                <input type="password" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} style={{display: 'block', marginBottom: '10px'}} />
                <button type="submit">Entrar</button>
            </form>
        </div>
    );
};

export default Login;
